    assignee: b['Assignee'] || 'Unassigned',
    description: b['Description'] || 'No description',
    comments: b['Latest Comments'],
    created_at: b['Created At'] || null,
    reported_date: now.toLocaleDateString('en-US', { timeZone: 'America/Chicago' })
  };
});

