const byStatus = bugs.reduce((acc, b) => {
  acc[b.status] = (acc[b.status] || 0) + 1;
  return acc;
}, {});

const byAssignee = bugs.reduce((acc, b) => {
  acc[b.assignee] = (acc[b.assignee] || 0) + 1;
  return acc;
}, {});

const byFolder = bugs.reduce((acc, b) => {
  acc[b.folder] = (acc[b.folder] || 0) + 1;
  return acc;
}, {});

const newToday = bugs.filter(b => b.created_at && parseInt(b.created_at) >= chicagoMidnight).length;
const backlog = bugs.filter(b => b.created_at && parseInt(b.created_at) < chicagoMidnight).length;

