const assigneeBreakdown = Object.entries(byAssignee).map(([k, v]) => `  - ${k}: ${v}`).join('\n');
const folderBreakdown = Object.entries(byFolder).map(([k, v]) => `  - ${k}: ${v}`).join('\n');

