    .replace(/\*\*\*(.*?)\*\*\*/g, '<strong><em>$1</em></strong>')
    // Bold (outside tables)
    .replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>')
    // Italic
    .replace(/\*(.*?)\*/g, '<em>$1</em>')
    // Horizontal rule
    .replace(/^---$/gm, '<hr>')
    // Numbered list items
    .replace(/^\d+\.\s+(.*$)/gm, '<li class="numbered">$1</li>')
    // Bullet list items
    .replace(/^-\s+(.*$)/gm, '<li class="bullet">$1</li>')
    // Wrap consecutive numbered items in <ol>
    .replace(/(<li class="numbered">.*<\/li>\n?)+/g, match => `<ol>${match}</ol>`)
    // Wrap consecutive bullet items in <ul>
    .replace(/(<li class="bullet">.*<\/li>\n?)+/g, match => `<ul>${match}</ul>`)
    // Paragraphs (Double line breaks)
    .replace(/\n\n/g, '</p><p>')
    // Single line breaks
    .replace(/\n/g, '<br>')
    // CLEANUP: Remove stray tags around block elements
