    .replace(/<\/ul><br>/g, '</ul>')
    .replace(/<\/ol><br>/g, '</ol>')
    .replace(/<\/div><br>/g, '</div>')
    .replace(/<br><ul/g, '<ul')
    .replace(/<br><ol/g, '<ol')
    .replace(/<p><div/g, '<div')
    .replace(/<\/div><\/p>/g, '</div>');

